from __future__ import annotations

import json
from html import escape
from typing import Mapping


class ApplicationLayoutPagesMixin:
    def _render_error(self, route: str, message: str) -> str:
        return self._layout(
            "页面渲染失败",
            "当前页面在读取服务层数据时发生错误。",
            self._notice(f"{escape(route)}: {escape(message)}", tone="danger"),
        )

    def _layout(
        self,
        page_title: str,
        subtitle: str,
        body_html: str,
        *,
        top_right_html: str | None = None,
        help_modal_sections: Mapping[str, str] | tuple[list[tuple[str, str]], Mapping[str, str]] | None = None,
        help_buttons: list[tuple[str, str]] | None = None,
    ) -> str:
        title = f"{page_title} | {self._title}"
        sidebar_nav = self._sidebar_nav(page_title)
        if isinstance(help_modal_sections, tuple):
            help_buttons, help_modal_sections = help_modal_sections
            help_buttons = list(help_buttons or [])
        if help_modal_sections is None:
            help_buttons, help_modal_sections = self._page_help_sections(page_title)
        help_buttons = help_buttons or [
            ("help-quickstart", "三步上手"),
            ("help-sampling", "怎么采样"),
            ("help-analysis", "怎么分析"),
        ]
        if top_right_html is None:
            top_right_html = self._performance_help_toolbar(buttons=help_buttons)
        top_actions = f"<div class='content-top-actions'>{top_right_html}</div>" if top_right_html else ""
        subtitle_html = subtitle if str(subtitle).lstrip().startswith("<") else f"<div class='notice'>{escape(subtitle)}</div>"
        if page_title == "Web 首页" and hasattr(self, "_portal_mode_notice"):
            subtitle_html = self._portal_mode_notice() + subtitle_html
        help_modal_html = self._performance_help_modal(help_modal_sections or {})
        return f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>{escape(title)}</title>
  <style>{_LAYOUT_CSS}</style>
</head>
<body>
  <div class="app-frame">
    <aside class="sidebar">
      <div class="sidebar-card">
        <div class="sidebar-title">Android<br>Stability Lab</div>
        <nav class="sidebar-nav">{sidebar_nav}</nav>
      </div>
    </aside>
    <main class="shell">
      <div class="content">
        <div class="content-topbar">
          {subtitle_html}
          {top_actions}
        </div>
        {body_html}
      </div>
    </main>
  </div>
  {help_modal_html}
  <script>{_LAYOUT_JS}</script>
</body>
</html>"""

    def _performance_help_toolbar(self, *, buttons: list[tuple[str, str]]) -> str:
        if not buttons:
            return ""
        toolbar_button_html = "".join(
            f"<button class='performance-help-btn' type='button' data-target-id='{escape(key, quote=True)}'>{escape(label)}</button>"
            for key, label in buttons
        )
        titles_json = json.dumps({key: label for key, label in buttons})
        return (
            "<div id='performance-help-root' class='performance-help-toolbar' "
            f"data-help-titles='{escape(titles_json, quote=True)}'>"
            + toolbar_button_html
            + "</div>"
        )

    def _help_card(
        self,
        title: str,
        content_lines: list[str],
        *,
        code: list[str] | None = None,
        links: list[tuple[str, str]] | None = None,
        meta: str | None = None,
    ) -> str:
        rows = "".join(f"<div>{escape(str(line))}</div>" for line in content_lines)
        if links:
            rows += "".join(f"<div>{self._route_link(label, path)}</div>" for label, path in links)
        if code:
            rows += "<pre class='mono'>" + escape("\n".join(code)) + "</pre>"
        if meta:
            rows += f"<div class='meta'>{escape(meta)}</div>"
        return f"<article class='card stack'><h3>{escape(title)}</h3>{rows}</article>"

    def _help_default_sections(self, page_title: str) -> dict[str, str]:
        title = page_title.lower()
        if "performance" in title:
            return {}
        links = [("首页", "/"), ("任务大厅", "/tasks"), ("性能采样", "/performance")]
        link_text = [("问题中心", "/issues")]
        if "任务" in page_title and "任务大厅" in page_title:
            links = [("任务定义", "/tasks"), ("Run 列表", "/tasks"), ("性能采样", "/performance")]
            link_text = [("问题定位", "/issues"), ("准入中心", "/admission")]
        elif "run" in title and "详情" in title:
            links = [("回任务大厅", "/tasks"), ("看 monitoring JSON", "/performance"), ("回首页", "/")]
            link_text = [("执行实例", "/tasks"), ("trace", "/performance")]
        elif "json api" in title or "接口" in page_title:
            links = [("首页 JSON", "/api/home"), ("性能 JSON", "/api/performance"), ("任务 JSON", "/api/tasks")]
            link_text = [("接口说明", "/json-api")]
        elif "问题" in page_title:
            links = [("未处理", "/issues"), ("按状态筛选", "/issues?state=processing"), ("问题详情", "/issues")]
            link_text = [("认领协作", "/issues")]
        elif "巡检" in page_title or "runner" in title:
            links = [("巡检总览", "/runner"), ("任务大厅", "/tasks"), ("首页", "/")]
            link_text = [("本地日志", "/runner")]
        elif "golden" in title:
            links = [("Golden Suite", "/goldens"), ("Diff", "/goldens/diff"), ("运行中任务", "/tasks")]
            link_text = [("样本定位", "/goldens")]
        elif "准入" in page_title:
            links = [("准入总览", "/admission"), ("准入详情", "/admission"), ("Run 详情", "/tasks")]
            link_text = [("latest audit", "/admission")]
        return {
            "help-quickstart": self._help_card(
                "1. 快速上手",
                ["先确认当前页面字段是否已加载出来。", "默认先看上方关键指标卡，确认本页有无异常状态。"],
                links=links,
                meta="先看结果面，再决定是否下钻。",
            ),
            "help-sampling": self._help_card(
                "2. 怎么采样",
                ["关注本页已展示的最新数据源、最新时间戳和关键计数。", "如需更细节，请使用左侧菜单切换到对应数据页再继续。"],
                links=link_text,
                meta="本页仅做入口与汇总，不替代任务内核。",
            ),
            "help-analysis": self._help_card(
                "3. 怎么分析",
                ["确认异常后，用页面上的 API 链接继续打开原始 JSON。", "必要时回到任务大厅/Run 详情对同一 run 做实例级检查。"],
            ),
        }


